#include <bits/stdc++.h>
using namespace std;
const int maxn=2e5+5;
int n,m,cnt1,cnt2,in[maxn],out[maxn],cur[maxn],tot;
vector<int> g[maxn];
vector<int> ans(maxn);
void dfs(int u) {
	for(int i=cur[u];i<g[u].size();i=cur[u]) {
		int v=g[u][i];
		cur[u]=i+1;
		dfs(v);
	}
	ans[++tot]=u;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1,u,v; i<=m; i++) {
		cin>>u>>v;
		g[u].emplace_back(v);
		out[u]++;
		in[v]++;
	}
	for(int i=1; i<=n; i++) {
		sort(g[i].begin(),g[i].end());
	}
	int st=1,ed=1;
	for(int i=1; i<=n; i++) {
		if(out[i]-in[i]==1) {
			st=i;
			cnt1++;
		} else if(in[i]-out[i]==1) {
			ed=i;
			cnt2++;
		} else if(in[i]!=out[i]) {
			cout<<"No";
			return 0;
		}
	}
	if(cnt1>1||cnt2>1) {
		cout<<"No";
		return 0;
	}
	dfs(st);
	for(int i=tot; i>=1; i--) {
		cout<<ans[i]<<" ";
	}
	return 0;
}
